    setExporting(true);
    try {
      await runExport();
    } finally {
      setExporting(false);
    }
  };

  return (
    <>
      <button onClick={() => setOpen(true)}>
        {exporting ? 'Exporting...' : 'Export'}
      </button>
      {open && <ExportWizard onExport={handleExport} onClose={() => setOpen(false)} />}
    </>
  );
}

